              </div>
              {isSelected && <Check className="w-4 h-4 text-indigo-600 shrink-0" />}
            </button>
          )
        })}
      </div>

      {filtered.length > 0 && (
        <p className="text-xs text-gray-400 text-center">{filtered.length} fonts · scroll to see more</p>
      )}
    </div>
  )
}

